import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"天罚之刃","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/天罚之刃.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/天罚之刃.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/天罚之刃.md"};function d(l,a,_,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"天罚之刃",tabindex:"-1"},[n("天罚之刃 "),e("a",{class:"header-anchor",href:"#天罚之刃","aria-label":'Permalink to "天罚之刃"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),s('<h1 id="天罚之刃-1" tabindex="-1">天罚之刃 <a class="header-anchor" href="#天罚之刃-1" aria-label="Permalink to &quot;天罚之刃&quot;">​</a></h1><p>天罚之刃<br> 价格：A+5000<br> 本质：魔幻本质<br> 天罚之刃是一把具有27L，破甲1，体积3的剑类武器，攻击时额外提供2个附加成功数。</p><p>天罚之刃造成的伤害始终视为亵渎能量伤害，当该武器进行攻击命中后，被命中的目标获得当前战斗轮*1层【罪业】，【罪业】层级正常叠加，战斗后自动消除。</p><p>【罪业】：持有该效果层数时，每层视为1点不可豁免的【恐惧不良点数】与【亵渎伤害易伤】，该易伤数值最多等同于当前进入战斗后经过轮数。<br> 该异常点数视为A级命运/诅咒来源，免疫异常点数将同时可以免疫易伤效果。</p><p>“若非天降灾殃，此物何以存世？”</p><p>天罚之刃具有两种额外效果，分别为【恶逆之心】与【骄盛的气焰】，持有该武器的单位可以在进入战斗场景后消费一个迅捷动作，并使每轮承受等同自身内在最高支线等级*1点不可避免的严重伤害，从而激活两者之一的效果，持续至该场景结束。</p><p>【恶逆之心】：“日暮穷途，故倒行逆施。”</p><p>每轮一次，你可以使受到的近战/远程伤害减少至原本的一半，但你必须在进入战斗后选择可减少的是近战还是远程类型伤害，这意味着上述减少伤害的分类（近战/远程）无法同时存在。</p><p>【骄盛的气焰】：“欲望只有升腾，以及升腾之后的嬗变。”<br> 每轮一次，你可以使攻击造成的伤害翻倍处理，同时若你对那次选择翻倍的攻击出目不满意，则还可以进行一次重骰，必须接受重骰后的结果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
